function dfs(graph, start) {
  const visited = new Set();
  function explore(node) {
    visited.add(node);
    for (const neighbor of graph.get(node) || []) {
      if (!visited.has(neighbor)) explore(neighbor);
    }
  }
  explore(start);
  return visited;
}

